content.problemStatement:
What will be the output of the following C program?

```c
#include

int main() {
    char text[] = "Hello World! C Programming";  // Input string
    int i = 0;  // Index for while loop
    int uppercaseCount = 0;  // Counter for uppercase letters

    // Loop through each character of the string
    while (text[i] != '\0') {  // Continue until null terminator
        // Check if the character is an uppercase letter
        if (text[i] >= 'A' && text[i] <= 'Z') {
            uppercaseCount++;  // Increment uppercase letter counter
        }
        i++;  // Move to the next character
    }

    // Print the total count of uppercase letters
    printf("Total uppercase letters: %d\n", uppercaseCount);

    return 0;
}
```

